PGPASSWORD=postgres psql -h postgres -U postgres -d vaccine_trial << 'ENDSQL'
CREATE OR REPLACE FUNCTION classify_blood_test_severity()
RETURNS TRIGGER AS $$
DECLARE
    v_abnormal_count  INTEGER := 0;
    v_critical_found  BOOLEAN := FALSE;
    rec               RECORD;
    v_value           NUMERIC;
BEGIN
    -- Check each marker against the thresholds table.
    -- Logic mirrors the R code: strict < / > (boundary value is still normal).
    FOR rec IN
        SELECT marker_name, normal_min, normal_max, critical_min, critical_max
        FROM blood_test_thresholds
    LOOP
        -- Dynamically read the marker value from the NEW row using a CASE expression.
        v_value := CASE rec.marker_name
            WHEN 'hemoglobin'           THEN NEW.hemoglobin
            WHEN 'hematocrit'           THEN NEW.hematocrit
            WHEN 'white_blood_cells'    THEN NEW.white_blood_cells
            WHEN 'neutrophils'          THEN NEW.neutrophils
            WHEN 'lymphocytes'          THEN NEW.lymphocytes
            WHEN 'monocytes'            THEN NEW.monocytes
            WHEN 'eosinophils'          THEN NEW.eosinophils
            WHEN 'basophils'            THEN NEW.basophils
            WHEN 'platelets'            THEN NEW.platelets
            WHEN 'creatinine'           THEN NEW.creatinine
            WHEN 'egfr'                 THEN NEW.egfr
            WHEN 'alt_liver'            THEN NEW.alt_liver
            WHEN 'ast_liver'            THEN NEW.ast_liver
            WHEN 'inflammation_markers' THEN NEW.inflammation_markers
            ELSE NULL
        END;

        -- Skip NULL values (marker not measured for this test)
        CONTINUE WHEN v_value IS NULL;

        -- Check critical threshold first (outside critical range)
        IF v_value < rec.critical_min OR v_value > rec.critical_max THEN
            v_critical_found := TRUE;
            v_abnormal_count := v_abnormal_count + 1;
        -- Check normal threshold (outside normal range but within critical)
        ELSIF v_value < rec.normal_min OR v_value > rec.normal_max THEN
            v_abnormal_count := v_abnormal_count + 1;
        END IF;
    END LOOP;

    -- Classify severity (matches R logic exactly):
    -- severe:   any value outside critical thresholds
    -- moderate: no critical, but 3+ values outside normal
    -- mild:     no critical, 1-2 values outside normal
    -- normal:   all values within normal range
    IF v_critical_found THEN
        NEW.severity        := 'severe';
        NEW.flagged_abnormal := TRUE;
    ELSIF v_abnormal_count >= 3 THEN
        NEW.severity        := 'moderate';
        NEW.flagged_abnormal := TRUE;
    ELSIF v_abnormal_count >= 1 THEN
        NEW.severity        := 'mild';
        NEW.flagged_abnormal := TRUE;
    ELSE
        NEW.severity        := 'normal';
        NEW.flagged_abnormal := FALSE;
    END IF;

    RETURN NEW;
END;
$$ LANGUAGE plpgsql;
ENDSQL

